  "type": "FLIP_CARD",
  "lessonText": "Learn key terms essential for getting started in cooking.",
  "data": {
    "cards": [
      {
        "front": "Mise en Place",
        "back": "A French term meaning 'everything in its place'. It refers to the preparation and organization of ingredients before cooking.",
        "icon": "📦"
      },
      {
        "front": "Sauté",
        "back": "A cooking method that involves cooking food quickly in a small amount of oil or fat over high heat.",
        "icon": "🔥"
      },
      {
        "front": "Simmer",
        "back": "To cook a liquid just below the boiling point, allowing small bubbles to form.",
        "icon": "💧"
      },
      {
        "front": "Al Dente",
        "back": "An Italian term used to describe pasta that is cooked until it is firm to the bite.",
        "icon": "🍝"
      }
    ]
  }
}
